// Deduplicate by link/URL, filter to last 24 hours, tag feedSource
// feedSource is the n8n node name that produced this item — used
// downstream by Format Telegram Message to split IDN vs international.
const items = $input.all();
const seen = new Set();
const now = new Date();
const cutoff = new Date(now.getTime() - 24 * 60 * 60 * 1000);

// Map n8n node name → stable source ID
const NODE_TO_SOURCE = {
  'Fetch Kontan': 'kontan-market',
  'Fetch Bisnis':  'bisnis-market',
  'Fetch Detik':   'detik-finance',
  'Fetch Reuters': 'reuters-indonesia',
};

const unique = [];
for (const item of items) {
  const link = item.json.link || item.json.guid || '';
  if (!link || seen.has(link)) continue;
  seen.add(link);

  const pubDate = item.json.pubDate || item.json.isoDate || '';
  if (pubDate) {
    const d = new Date(pubDate);
    if (d < cutoff) continue;
  }

  // Resolve feedSource: prefer existing field, fall back to node-name map
  const nodeName = item.json.$node || '';
  const feedSource =
    item.json.feedSource ||
    NODE_TO_SOURCE[nodeName] ||
    'unknown';

  unique.push({
    json: {
      title:      item.json.title || 'No title',
      link:       link,
      pubDate:    pubDate,
      content:    item.json.contentSnippet || item.json.content || item.json.description || '',
      source:     feedSource,
      category:   item.json.categories ? item.json.categories[0] : 'general',
    }
  });
}

if (unique.length === 0) {
  return [{ json: { title: 'No recent news found', link: '', pubDate: new Date().toISOString(), content: '', source: 'system', category: 'none' } }];
}

return unique;

// ============================================================
// SCORING MODULE v0.1.0
// Signals: Recency (decay) + Ticker (NER) + Keyword (lexicon)
// ============================================================

// ── Configuration ──
const CONFIG = {
  recency: { halfLife: 6, maxScore: 30, fallback: 15 },
  ticker:  { maxScore: 35 },
  keyword: { maxScore: 15 },
  topN: 10
};

const DECAY_LAMBDA = Math.LN2 / CONFIG.recency.halfLife;

// ── Watchlist: Tiered LQ45 tickers ──
// Heuristic engineering weights for market importance.
const WATCHLIST = {
  BBCA:15, BBRI:15, BMRI:15, TLKM:15, ASII:15,
  BBNI:15, GOTO:15, AMMN:15, BREN:15, BYAN:15,
  ADRO:10, PTBA:10, ANTM:10, MDKA:10, INDF:10,
  ICBP:10, UNVR:10, KLBF:10, SMGR:10, INTP:10, BRIS:10,
  EXCL:5, MTEL:5, BUKA:5
};

// Single compiled regex — O(n) single-pass scan
const TICKER_PATTERN = new RegExp(
  '\\b(' + Object.keys(WATCHLIST).join('|') + ')\\b', 'gi'
);

// ── Keyword Tiers: Financial Event Lexicon ──
// Heuristic keyword lexicon for market-impacting events.
// Returns HIGHEST matching tier only (no summing across tiers).
const KEYWORD_TIERS = [
  {
    name: 'high', pts: 15,
    words: [
      'dividen','dividend','stock split','pemecahan saham',
      'merger','akuisisi','takeover','ipo','rights issue','buyback',
      'default','gagal bayar','bangkrut','pailit',
      'suspensi','delisting','bi rate','suku bunga'
    ]
  },
  {
    name: 'medium', pts: 8,
    words: [
      'laba bersih','pendapatan','laporan keuangan','earnings',
      'profit','revenue','rups','dividend payout','eps','roe'
    ]
  },
  {
    name: 'low', pts: 4,
    words: [
      'rekomendasi','target harga','price target',
      'upgrade','downgrade','outlook','analis'
    ]
  }
];

// ── Signal 1: Recency Score ──
// score = maxScore × e^(−λ × Δh), λ = ln(2)/halfLife
function recencyScore(pubDate, now) {
  const { maxScore, fallback } = CONFIG.recency;
  if (!pubDate) return fallback;
  const pubMs = Date.parse(pubDate);
  if (Number.isNaN(pubMs)) return fallback;
  const hoursAgo = (now.getTime() - pubMs) / 3600000;
  const deltaH = Math.max(0, hoursAgo);
  return Math.round(maxScore * Math.exp(-DECAY_LAMBDA * deltaH) * 100) / 100;
}

// ── Signal 2: Ticker Match ──
function tickerMatch(title, content) {
  const text = ((title || '') + ' ' + (content || '')).toUpperCase();
  TICKER_PATTERN.lastIndex = 0;
  const found = new Set();
  let m;
  while ((m = TICKER_PATTERN.exec(text)) !== null) found.add(m[1]);
  const tickers = Array.from(found);
  let raw = 0;
  for (const t of tickers) raw += WATCHLIST[t] || 0;
  return { score: Math.min(raw, CONFIG.ticker.maxScore), tickers };
}

// ── Signal 3: Keyword Boost ──
// Heuristic financial event lexicon — NOT sentiment analysis.
// Returns highest matching tier score only.
function keywordScore(title, content) {
  const text = ((title || '') + ' ' + (content || '')).toLowerCase();
  for (const tier of KEYWORD_TIERS) {
    for (const word of tier.words) {
      if (text.indexOf(word) !== -1) {
        return { score: tier.pts, keyword: word };
      }
    }
  }
  return { score: 0, keyword: null };
}

// ── Final Score ──
// finalScore = recencyScore + tickerScore + keywordScore (max ≈ 80)
function finalScore(r, t, k) {
  return Math.round((r + t + k) * 100) / 100;
}

// ── Main ──
const items = $input.all();
const now = new Date();

const scored = items.map(item => {
  const a = item.json;
  const rScore  = recencyScore(a.pubDate, now);
  const tResult = tickerMatch(a.title, a.content);
  const kResult = keywordScore(a.title, a.content);
  const fScore  = finalScore(rScore, tResult.score, kResult.score);
  return {
    json: {
      ...a,
      recencyScore: rScore,
      tickerScore:  tResult.score,
      tickers:      tResult.tickers,
      keywordScore: kResult.score,
      matchedKeyword: kResult.keyword,
      finalScore:   fScore
    }
  };
});

scored.sort((a, b) => b.json.finalScore - a.json.finalScore);
return scored.slice(0, CONFIG.topN);

// ============================================================
// FORMAT TELEGRAM MESSAGE — v0.1.1
// Style A (compact/terminal) + Style C news segmentation
// No emoji. Telegram Markdown-safe. 4096-char guard.
// ============================================================

const IDN_SOURCES = new Set([
  'kontan-market', 'bisnis-market', 'detik-finance'
]);

const SOURCE_LABEL = {
  'kontan-market':     'Kontan',
  'bisnis-market':     'Bisnis.com',
  'detik-finance':     'Detik Finance',
  'reuters-indonesia': 'Reuters',
  'bloomberg':         'Bloomberg',
};

const SEP = '─────────────────────────';
const MAX_CHARS = 4096;

// ── Helpers ──────────────────────────────────────────────

function wibNow(date) {
  return new Date(date.getTime() + 7 * 3600000);
}

function dateStr(date) {
  const d = wibNow(date);
  const months = ['January','February','March','April','May','June',
                  'July','August','September','October','November','December'];
  return `${d.getUTCDate()} ${months[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
}

function timeStr(date) {
  const d = wibNow(date);
  return `${String(d.getUTCHours()).padStart(2,'0')}:${String(d.getUTCMinutes()).padStart(2,'0')} WIB`;
}

function edition(date) {
  return wibNow(date).getUTCHours() < 12 ? 'Morning Edition' : 'Afternoon Edition';
}

// Escape Telegram Markdown special chars inside link label text
function escMd(str) {
  return (str || '').replace(/([_*`\[\]])/g, '\\$1');
}

function articleTimeStr(pubDate) {
  if (!pubDate) return '';
  const d = new Date(pubDate);
  if (isNaN(d)) return '';
  return timeStr(d);
}

function srcLabel(src) {
  return SOURCE_LABEL[src] || src || 'Unknown';
}

// ── Inputs ────────────────────────────────────────────────

const items = $input.all();
const now   = new Date();

const idnItems  = items.filter(i => IDN_SOURCES.has(i.json.source));
const intlItems = items.filter(i => !IDN_SOURCES.has(i.json.source));

// ── PART 1: Header + Market Data ─────────────────────────
// Commodity, gainers, and corporate action are placeholder
// sections. Wire a live-data node upstream and replace these
// static strings with $('Live Data').first().json.* expressions.

let part1 = '';
part1 += `*IDN Market Briefing - ${edition(now)}*\n`;
part1 += `${dateStr(now)} | ${timeStr(now)}\n`;
part1 += `${SEP}\n`;

part1 += `\n*COMMODITY STATS*\n`;
part1 += `Palm Oil   : 4,820 MYR/t   +1.2%\n`;
part1 += `Coal       :   138.5 USD/t  -0.4%\n`;
part1 += `Nickel     : 16,340 USD/t  +0.8%\n`;
part1 += `CPO Index  :  4,105         +0.6%\n`;

part1 += `\n${SEP}\n`;
part1 += `*TOP GAINERS - IDN STOCK*\n`;
part1 += `Ticker  Daily   Weekly  Monthly\n`;
part1 += `BBCA   +3.41%  +5.20%  +12.4%\n`;
part1 += `GOTO   +2.87%  +4.10%   +8.7%\n`;
part1 += `BMRI   +2.10%  +3.80%   +9.2%\n`;
part1 += `ADRO   +1.95%  +6.40%  +18.1%\n`;
part1 += `MTEL   +1.80%  +2.90%   +7.6%\n`;

part1 += `\n*TOP GAINERS - US STOCK*\n`;
part1 += `Ticker  Daily   Weekly  Monthly\n`;
part1 += `NVDA   +4.21%  +9.20%  +31.5%\n`;
part1 += `TSLA   +3.18%  +6.80%  +22.4%\n`;
part1 += `META   +2.90%  +8.75%  +19.8%\n`;
part1 += `AMZN   +1.75%  +5.90%  +14.2%\n`;
part1 += `GOOG   +1.40%  +4.10%  +11.3%\n`;

part1 += `\n*TOP GAINERS - CRYPTO*\n`;
part1 += `Ticker  Daily   Weekly  Monthly\n`;
part1 += `BTC    +2.90%  +8.40%  +22.4%\n`;
part1 += `SOL    +4.11% +12.30%  +31.2%\n`;
part1 += `ETH    +1.80%  +7.80%  +18.9%\n`;
part1 += `BNB    +2.10%  +5.50%  +14.5%\n`;
part1 += `AVAX   +3.50% +10.20%  +28.3%\n`;

part1 += `\n${SEP}\n`;
part1 += `*CORPORATE ACTION - IDN*\n`;
part1 += `BBRI  Dividend      Rp 200/share   Record 20 Mar\n`;
part1 += `TLKM  Rights Issue  1:5            Exercise 25 Mar\n`;
part1 += `GOTO  Stock Split   1:10           Effective 1 Apr\n`;

// ── PART 2: News sections ─────────────────────────────────

let part2 = '';

part2 += `${SEP}\n`;
part2 += `*# IDN NEWS*\n`;
if (idnItems.length === 0) {
  part2 += `_Tidak ada berita IDN terbaru._\n`;
} else {
  idnItems.forEach((item, i) => {
    const a   = item.json;
    const t   = articleTimeStr(a.pubDate);
    const src = srcLabel(a.source);
    part2 += `${i + 1}. [${escMd(a.title)}](${a.link})\n`;
    part2 += `   ${src}${t ? ' | ' + t : ''}\n`;
  });
}

part2 += `\n*# INTERNATIONAL NEWS*\n`;
if (intlItems.length === 0) {
  part2 += `_No international news available._\n`;
} else {
  intlItems.forEach((item, i) => {
    const a   = item.json;
    const t   = articleTimeStr(a.pubDate);
    const src = srcLabel(a.source);
    part2 += `${i + 1}. [${escMd(a.title)}](${a.link})\n`;
    part2 += `   ${src}${t ? ' | ' + t : ''}\n`;
  });
}

part2 += `\n${SEP}\n`;
part2 += `_IDN-StockNews v0.1.0_`;

// ── 4096-char guard ──────────────────────────────────────
// Try full message first. If over limit, send as two messages.

const fullMsg = part1 + '\n' + part2;
const results = [];

if (fullMsg.length <= MAX_CHARS) {
  results.push({
    json: {
      text:           fullMsg,
      parse_mode:     'Markdown',
      disable_web_page_preview: true,
      article_count:  items.length,
      idn_count:      idnItems.length,
      intl_count:     intlItems.length,
      edition:        edition(now),
      generated_at:   now.toISOString(),
      split:          false,
    }
  });
} else {
  const footer = `\n${SEP}\n_IDN-StockNews v0.1.0_`;
  results.push(
    {
      json: {
        text:       part1.trimEnd() + footer,
        parse_mode: 'Markdown',
        disable_web_page_preview: true,
        split: true, part: 1,
      }
    },
    {
      json: {
        text:       part2,
        parse_mode: 'Markdown',
        disable_web_page_preview: true,
        split: true, part: 2,
      }
    }
  );
}

return results;
